class Solution {
    /**
     * @param nums The input integer array.
     * @return The count of "good" subarrays.
     */
    def nums(nums: Array[Long]): Long = {
        val n = nums.length
        var count: Long = 0

        // Iterate over all possible starting positions i
        for (i <- 0 until n) {
            var currentOr: Long = 0
            // Keep track of the elements encountered in the current subarray starting at i
            val encounteredElements = IntSet.empty[Long] 

            // Iterate over all possible ending positions j >= i
            for (j <- i until n) {
                val element = nums(j)

                // Update the bitwise OR of the subarray nums[i..j]
                currentOr = currentOr | element

                // Add the current element to the set of encountered elements
                encounteredElements.add(element)

                // Check the condition: 
                // The bitwise OR of the subarray must equal at least one element present in the subarray.
                // Since the OR operation is non-decreasing (currentOr | next_element >= currentOr), 
                // the condition is equivalent to checking if currentOr is equal to any element in the set.

                var isGood = false
                for (e <- encounteredElements) {
                    if (currentOr == e) {
                        isGood = true
                        break
                    }
                }

                if (isGood) {
                    count += 1
                }
            }
        }

        count
    }
