  /**
   * 如果一个子数组中所有元素的按位或等于该子数组中至少出现一次的元素，则称其为“好”子数组。
   * 返回 nums 中好子数组的数量。
   * 
   * @param nums 整数数组
   * @return 好子数组的数量
   */
  def nums(nums: Array[Long]): Long = {
    val n = nums.length
    var goodSubarraysCount: Long = 0

    // 遍历所有可能的子数组起点 i
    for (i <- 0 until n) {
      var currentOr: Long = 0 // 当前子数组 [i..j] 的按位或
      // 用于快速检查是否有元素等于 currentOr 的集合
      val seenElements = new HashSet[Long]() 

      // 遍历所有可能的子数组终点 j (j >= i)
      for (j <- i until n) {
        val numJ = nums(j)

        // 1. 更新当前子数组 [i..j] 的按位或
        val newOr = currentOr | numJ

        // 2. 更新 seenElements 集合
        seenElements.add(numJ)

        // 3. 检查是否满足条件：(currentOr | numJ) == 至少出现一次的元素
        // 条件是：子数组的 OR 值 (newOr) 必须存在于该子数组的元素中。
        if (seenElements.contains(newOr)) {
          goodSubarraysCount += 1
        }

        // 4. 更新 currentOr
        currentOr = newOr
      }
    }

    goodSubarraysCount
  }
}
