import scala.collection.mutable

object Solution {
  /**
   * 检查一个子数组 [l, r] 是否是“好”子数组。
   * 一个子数组是好子数组，如果它所有元素的按位或等于该子数组中至少出现一次的元素。
   * 
   * 由于子数组的按位或是所有元素按位或的结果，如果这个结果等于子数组中某个元素 a，
   * 那么这个结果 (OR_val) 必须满足 OR_val = a。
   * 
   * 此外，如果 OR_val = a，由于 OR_val 是所有元素的按位或，那么 a 必须是所有元素按位或的子集。
   * 但由于 a 是子数组中的一个元素，所以 a 已经是所有元素的按位或的子集。
   * 
   * 关键点在于：如果 OR_val = a，这意味着所有其他元素 b 在子数组中，都满足 b | a = a。
   * 这等价于说，所有其他元素 b 都是 a 的子集（即 b & ~a == 0）。
   * 
   * 最终条件可以简化为：子数组的和的按位或 (OR_val) 必须等于子数组中至少一个元素 a。
   * 如果 OR_val = a，那么 a 必须等于子数组的按位或。
   */
  def nums(nums: Array[Long]): Long = {
    val n = nums.length
    var count: Long = 0

    // 遍历所有可能的起始点 l
    for (l <- 0 until n) {
      var currentOr: Long = 0
      // 记录当前子数组 [l, r] 中出现过的元素，以检查“存在于子数组中”的条件
      // 这里我们不需要显式记录所有元素，因为我们只需要知道最终的按位或是否等于某个元素。

      // 遍历所有可能的结束点 r >= l
      for (r <- l until n) {
        val newElement = nums(r)
        currentOr = currentOr | newElement

        // 子数组是 nums[l..r]
        // 1. 子数组的按位或是 currentOr。
        // 2. 判断 currentOr 是否等于该子数组中至少出现一次的元素。

        // 如果 currentOr 等于子数组中至少一个元素 a，那么 a 必须满足 a = currentOr。
        // 这意味着我们只需要检查 nums[l..r] 中是否包含元素 currentOr。

        var foundMatch = false
        for (k <- l to r) {
          if (nums(k) == currentOr) {
            foundMatch = true
            break
          }
        }

        if (foundMatch) {
          count += 1
        }
      }
    }
    count
  }
}
